96	function DesktopChatItem({
97	  chat, isActive, isRenaming, renameValue, indent = false,
98	  onSelect, onRenameChange, onRenameSubmit, onRenameCancel, onStartRename, onPin, onDelete,
99	}: DesktopChatItemProps) {
100	  const [hovered, setHovered] = useState(false);
101	  const showMenu = isActive || hovered;
102	
103	  return (
104	    <div
105	      onClick={() => { if (!isRenaming) onSelect(); }}
106	      onMouseEnter={() => setHovered(true)}
107	      onMouseLeave={() => setHovered(false)}
108	      style={{ position: 'relative' }}
109	      className={`flex items-center gap-2 ${indent ? 'py-2.5 pl-7 pr-8' : 'py-3.5 pl-2.5 pr-8'} rounded-lg cursor-pointer transition-all ${
110	        isActive ? 'bg-bronze/10 text-foreground' : 'text-muted-foreground hover:bg-muted/50 hover:text-foreground'
111	      }`}
112	    >
113	      <MessageSquare className={`w-${indent ? '3.5' : '4'} h-${indent ? '3.5' : '4'} flex-shrink-0 ${isActive ? 'text-bronze' : ''}`} />
