115	      {isRenaming ? (
116	        <input
117	          autoFocus
118	          value={renameValue}
119	          onChange={(e) => onRenameChange(e.target.value)}
120	          onKeyDown={(e) => {
121	            if (e.key === 'Enter') onRenameSubmit();
122	            if (e.key === 'Escape') onRenameCancel();
123	          }}
