import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { 
  Plus, 
  Search, 
  FileText, 
  Send, 
  Eye,
  MoreHorizontal,
  Edit,
  Trash2,
  CheckCircle2,
  Clock,
  AlertCircle,
  XCircle,
  Receipt,
  Copy,
  Filter,
  ArrowUpDown,
  TrendingUp,
  DollarSign,
  Sparkles,
} from "lucide-react";
import { toast } from "sonner";
import { format, isAfter } from "date-fns";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import CreateInvoiceDialog from "./CreateInvoiceDialog";
import { useSubscription } from "@/hooks/use-subscription";
import InvoicePreviewDialog from "./InvoicePreviewDialog";
import ReceiptPreviewDialog from "./ReceiptPreviewDialog";

interface Invoice {
  id: string;
  invoice_number: string;
  client_name: string;
  client_email: string | null;
  issue_date: string;
  due_date: string;
  status: string;
  subtotal: number;
  total: number;
  currency: string;
  created_at: string;
  accent_color: string | null;
}

const SmartInvoicesTab = ({ workspaceId }: { workspaceId?: string } = {}) => {
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [sortBy, setSortBy] = useState<"newest" | "oldest" | "amount">("newest");
  const { limits, isFree, invoicesUsedThisMonth } = useSubscription();
  const invoiceLimitReached = isFree && invoicesUsedThisMonth >= limits.invoicesPerMonth;
  const [createDialogOpen, setCreateDialogOpen] = useState(false);
  const [editingInvoice, setEditingInvoice] = useState<Invoice | null>(null);
  const [previewInvoice, setPreviewInvoice] = useState<Invoice | null>(null);
  const [receiptInvoice, setReceiptInvoice] = useState<Invoice | null>(null);
  const [businessSettings, setBusinessSettings] = useState<{
    business_name: string;
    business_email: string;
    business_phone: string;
    business_address: string;
    logo_url: string;
    tax_id: string;
    default_currency: string;
    default_tax_rate: number;
    default_payment_terms: string;
  } | null>(null);

  const fetchInvoices = async () => {
    const { data: { session } } = await supabase.auth.getSession();
    if (!session) return;

    if (workspaceId) {
      const { data: msgs } = await supabase
        .from("chat_messages")
        .select("invoice_id")
        .eq("room_id", workspaceId)
        .not("invoice_id", "is", null);
      const ids = [...new Set((msgs || []).map((m: any) => m.invoice_id).filter(Boolean))];
      if (ids.length === 0) { setInvoices([]); setLoading(false); return; }
      const { data, error } = await supabase.from("invoices").select("*").in("id", ids).order("created_at", { ascending: false });
      if (error) { toast.error("Failed to load invoices"); return; }

