@tailwind base;
@tailwind components;
@tailwind utilities;

/* Definition of the design system. All colors, gradients, fonts, etc should be defined here. 
All colors MUST be HSL.
*/

@layer base {
  :root {
    /* Crevia Brand Colors */
    --background: 0 0% 100%;
    --foreground: 0 0% 0%;

    --bronze: 23 87% 56%; /* #f0782f - Premium bronze */
    --bronze-light: 23 87% 66%;
    --bronze-dark: 23 87% 45%;

    --card: 0 0% 100%;
    --card-foreground: 0 0% 0%;

    --popover: 0 0% 100%;
    --popover-foreground: 0 0% 0%;

    --primary: 23 87% 56%; /* #f0782f - Premium bronze as primary */
    --primary-foreground: 0 0% 100%;

    --secondary: 0 0% 96%;
    --secondary-foreground: 0 0% 0%;

    --muted: 0 0% 96%;
    --muted-foreground: 0 0% 15%;

    --accent: 23 87% 56%;
    --accent-foreground: 0 0% 100%;

    --destructive: 0 84.2% 60.2%;
    --destructive-foreground: 0 0% 100%;

    --border: 0 0% 90%;
    --input: 0 0% 90%;
    --ring: 23 87% 56%;

    --radius: 0.75rem; /* 12px as per spec */

    /* Gradients */
    --gradient-bronze: linear-gradient(135deg, hsl(var(--bronze)), hsl(var(--bronze-light)));
    --gradient-hero: linear-gradient(180deg, hsl(var(--background)), hsl(var(--secondary)));

    /* Shadows - Premium Apple-style */
    --shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.05);
    --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.1);
    --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.1);
    --shadow-xl: 0 20px 25px -5px rgb(0 0 0 / 0.1);

    /* Transitions */
    --transition-smooth: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  }

  .dark {
    --background: 240 8% 10%;
    --foreground: 0 0% 97%; /* Crisp near-white — neutral, not creamy */

    --card: 240 8% 13%;
    --card-foreground: 0 0% 97%;

    --popover: 240 10% 9%;
    --popover-foreground: 0 0% 97%;

    --primary: 23 87% 56%;
    --primary-foreground: 0 0% 100%;

    --secondary: 240 6% 14%;
    --secondary-foreground: 0 0% 95%;

    --muted: 240 6% 14%;
    --muted-foreground: 0 0% 88%; /* Up from 82% — clearly readable, still subordinate */

    --accent: 23 87% 56%;
    --accent-foreground: 0 0% 100%;

