83	  userId,
84	}: WorkspaceInboxListProps) => {
85	  const [rooms, setRooms] = useState<Room[]>([]);
86	  const [loading, setLoading] = useState(true);
87	  const [search, setSearch] = useState("");
88	
89	  // Workspace CRUD state
90	  const [renameDialog, setRenameDialog] = useState<Room | null>(null);
91	  const [renameValue, setRenameValue] = useState("");
92	  const [renaming, setRenaming] = useState(false);
93	  const [deleteConfirm, setDeleteConfirm] = useState<Room | null>(null);
94	  const [deleting, setDeleting] = useState(false);
95	
96	  // New workspace dialog state
97	  const [createDialogOpen, setCreateDialogOpen] = useState(false);
98	  const [createName, setCreateName] = useState("");
99	  const [creating, setCreating] = useState(false);
100	
101	  // New DM dialog state
102	  const [dmDialogOpen, setDmDialogOpen] = useState(false);
103	  const [allUsers, setAllUsers] = useState<any[]>([]);
104	  const [userSearch, setUserSearch] = useState("");
105	  const [loadingUsers, setLoadingUsers] = useState(false);
106	  const [startingDM, setStartingDM] = useState<string | null>(null);
107	
108	  useEffect(() => {
109	    if (!userId) return;
110	    fetchRooms();
111	
112	    // Real-time: bump a room to the top whenever a new message arrives
113	    const channel = supabase
114	      .channel(`inbox:${userId}`)
115	      .on(
116	        "postgres_changes",
117	        { event: "UPDATE", schema: "public", table: "chat_rooms" },
118	        (payload) => {
119	          const updated = payload.new as { id: string; updated_at: string };
120	          setRooms((prev) => {
121	            const idx = prev.findIndex((r) => r.id === updated.id);
122	            if (idx === -1) return prev;
123	            const room = { ...prev[idx], updated_at: updated.updated_at };
124	            const rest = prev.filter((_, i) => i !== idx);
125	            return [room, ...rest];
126	          });
127	        }
128	      )
129	      .on(
130	        "postgres_changes",
131	        { event: "INSERT", schema: "public", table: "chat_room_members", filter: `user_id=eq.${userId}` },
132	        () => {
133	          // A new room was shared with this user — refresh the full list
134	          fetchRooms();
135	        }
136	      )
137	      .subscribe();
138	
139	    return () => { supabase.removeChannel(channel); };
140	  }, [userId]);
141	
142	  // Sync DM partner avatar changes in real time
143	  useEffect(() => {
144	    if (!userId) return;
145	    const ch = supabase
146	      .channel(`profile-sync-inbox:${userId}`)
147	      .on(
148	        "postgres_changes",
149	        { event: "UPDATE", schema: "public", table: "profiles" },
150	        (payload) => {
151	          const updated = payload.new as any;
152	          setRooms((prev) =>
153	            prev.map((room) => {
154	              if (!room.is_group && room.memberUserIds?.includes(updated.id)) {
155	                return {
156	                  ...room,
157	                  dmPartnerAvatar: updated.avatar_url ?? room.dmPartnerAvatar,
158	                  dmPartnerName: updated.display_name ?? room.dmPartnerName,
159	                };
160	              }
161	              return room;
162	            })
163	          );
164	        }
165	      )
166	      .subscribe();
167	    return () => { supabase.removeChannel(ch); };
168	  }, [userId]);
169	
