296	    setDmDialogOpen(true);
297	    setUserSearch("");
298	    if (!allUsers.length) {
299	      setLoadingUsers(true);
300	      const { data } = await supabase
301	        .from("profiles")
302	        .select("id, display_name, handle, avatar_url, user_type")
303	        .neq("id", userId)
304	        .order("display_name");
305	      setAllUsers(data || []);
306	      setLoadingUsers(false);
307	    }
308	  };
309	
310	  const startDirectChat = async (otherUserId: string) => {
311	    setStartingDM(otherUserId);
312	    try {
313	      // Check for existing DM room between these two users
314	      const { data: myRooms } = await supabase
315	        .from("chat_room_members")
316	        .select("room_id")
317	        .eq("user_id", userId);
318	
319	      const { data: theirRooms } = await supabase
320	        .from("chat_room_members")
321	        .select("room_id")
322	        .eq("user_id", otherUserId);
323	
324	      if (myRooms && theirRooms) {
325	        const myRoomIds = new Set(myRooms.map((r) => r.room_id));
326	        const commonIds = theirRooms
327	          .filter((r) => myRoomIds.has(r.room_id))
328	          .map((r) => r.room_id);
329	
330	        if (commonIds.length > 0) {
331	          const { data: existing } = await supabase
332	            .from("chat_rooms")
333	            .select("*")
334	            .in("id", commonIds)
335	            .eq("is_group", false)
336	            .is("name", null);
337	
338	          if (existing?.length) {
339	            setDmDialogOpen(false);
340	            // Find or add to rooms list
341	            const existingInList = rooms.find((r) => r.id === existing[0].id);
342	            if (existingInList) {
343	              onSelectRoom(existingInList, "dm");
344	            } else {
345	              await fetchRooms();
346	              onSelectRoom({ ...existing[0], memberCount: 2 }, "dm");
347	            }
348	            return;
349	          }
350	        }
351	      }
352	
353	      // Create new DM room
354	      const { data: room, error } = await supabase
355	        .from("chat_rooms")
356	        .insert({ created_by: userId, is_group: false })
357	        .select()
358	        .single();
359	
360	      if (error || !room) { toast.error("Failed to start conversation"); return; }
361	
362	      await supabase.from("chat_room_members").insert([
363	        { room_id: room.id, user_id: userId, role: "admin" },
364	        { room_id: room.id, user_id: otherUserId, role: "member" },
365	      ]);
366	
367	      setDmDialogOpen(false);
368	      await fetchRooms();
369	      onSelectRoom({ ...room, memberCount: 2 }, "dm");
370	    } finally {
371	      setStartingDM(null);
372	    }
373	  };
374	
375	  const q = search.toLowerCase();
376	  const workspaces = rooms.filter(
377	    (r) => r.name !== null && (!q || r.name!.toLowerCase().includes(q))
378	  );
379	  const dms = rooms.filter(
380	    (r) =>
381	      r.name === null &&
382	      !r.is_group &&
383	      (!q || (r.dmPartnerName ?? "").toLowerCase().includes(q))
384	  );
385	
386	  const filteredUsers = allUsers.filter((u) => {
387	    const term = userSearch.toLowerCase();
388	    return (
389	      !term ||
390	      u.display_name?.toLowerCase().includes(term) ||
391	      u.handle?.toLowerCase().includes(term)
392	    );
393	  });
394	
395	  const SkeletonItem = () => (
396	    <div className="flex items-center gap-2.5 p-2.5 rounded-xl">
397	      <div className="w-9 h-9 rounded-xl bg-muted animate-pulse flex-shrink-0" />
398	      <div className="flex-1 space-y-1.5">
399	        <div className="h-2.5 bg-muted animate-pulse rounded w-3/4" />
400	        <div className="h-2 bg-muted animate-pulse rounded w-1/2" />
401	      </div>
402	    </div>
403	  );
404	
405	  return (
406	    <>
407	      <div className="flex flex-col w-[268px] xl:w-[295px] flex-shrink-0 border-r border-gray-100 dark:border-border/60 bg-background overflow-hidden">
408	        {/* Header — search only, no "New" button */}
409	        <div className="px-3 pt-3 pb-2.5 border-b border-gray-100 dark:border-border/50 flex-shrink-0 space-y-2.5">
410	          <h3 className="font-semibold text-sm tracking-tight">Messages</h3>
411	          <div className="relative">
412	            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-muted-foreground/60" />
413	            <Input
414	              value={search}
415	              onChange={(e) => setSearch(e.target.value)}
416	              placeholder="Search..."
417	              className="pl-8 h-8 text-xs bg-gray-50 dark:bg-muted/40 border-gray-100 dark:border-border/50 focus-visible:ring-bronze/30"
418	            />
419	          </div>
420	        </div>
421	
422	        <ScrollArea className="flex-1">
423	          <div className="p-2 space-y-4">
424	            {/* Active Workspaces */}
425	            <div>
426	              <div className="flex items-center justify-between px-2 py-1.5">
427	                <p className="text-[10px] font-semibold text-muted-foreground/50 uppercase tracking-widest">
428	                  Active Workspaces
429	                </p>
430	                <button
431	                  onClick={() => { setCreateName(""); setCreateDialogOpen(true); }}
432	                  title="New workspace"
433	                  className="w-5 h-5 flex items-center justify-center rounded-md text-muted-foreground/50 hover:text-bronze hover:bg-bronze/10 transition-all duration-150"
434	                >
435	                  <Plus className="w-3.5 h-3.5" />
436	                </button>
437	              </div>
438	
439	              {loading ? (
440	                <div className="space-y-0.5">
441	                  {[...Array(3)].map((_, i) => (
442	                    <SkeletonItem key={i} />
443	                  ))}
444	                </div>
445	              ) : workspaces.length === 0 ? (
446	                <div className="px-2 py-5 text-center">
447	                  <Sparkles className="w-6 h-6 text-muted-foreground/20 mx-auto mb-2" />
448	                  <p className="text-[11px] text-muted-foreground">
449	                    No workspaces yet
450	                  </p>
451	                  <button
452	                    onClick={() => { setCreateName(""); setCreateDialogOpen(true); }}
453	                    className="text-[11px] text-bronze hover:underline mt-1"
454	                  >
455	                    Create one
456	                  </button>
457	                </div>
458	              ) : (
459	                <div className="space-y-0.5">
460	                  {workspaces.map((room, idx) => {
461	                    const isSelected = selectedRoomId === room.id;
462	                    return (
463	                      <motion.div
464	                        key={room.id}
465	                        initial={{ opacity: 0, y: 6 }}
466	                        animate={{ opacity: 1, y: 0 }}
467	                        transition={{ duration: 0.2, delay: idx * 0.04 }}
468	                        className={cn(
469	                          "relative flex items-center rounded-xl transition-all duration-150 group",
470	                          isSelected
471	                            ? "bg-bronze/10 border border-bronze/20 shadow-sm"
472	                            : "hover:bg-gray-50 dark:hover:bg-muted/50 border border-transparent"
473	                        )}
474	                      >
475	                        {/* Selectable area */}
476	                        <button
477	                          onClick={() => onSelectRoom(room, "workspace")}
478	                          className="flex-1 text-left p-2.5 min-w-0"
479	                        >
480	                          <div className="flex items-center gap-2.5">
481	                            <div className={cn(
482	                              "w-9 h-9 rounded-xl flex items-center justify-center flex-shrink-0 transition-all duration-150",
483	                              isSelected ? "bg-bronze/20" : "bg-gray-100 dark:bg-muted group-hover:bg-bronze/10"
484	                            )}>
485	                              <Sparkles className={cn(
486	                                "w-4 h-4 transition-colors duration-150",
487	                                isSelected ? "text-bronze" : "text-muted-foreground/50 group-hover:text-bronze/60"
488	                              )} />
489	                            </div>
490	                            <div className="min-w-0 flex-1">
491	                              <div className="flex items-center justify-between gap-1 mb-0.5">
492	                                <p className={cn(
493	                                  "text-[12px] font-semibold truncate leading-snug",
494	                                  isSelected ? "text-foreground" : "text-foreground/85"
495	                                )}>
496	                                  {room.name}
497	                                </p>
498	                                <span className="text-[9px] text-muted-foreground/50 whitespace-nowrap flex-shrink-0">
499	                                  {timeAgo(room.updated_at)}
500	                                </span>
501	                              </div>
502	                              <div className="flex items-center gap-1.5">
503	                                <Users className="w-2.5 h-2.5 text-muted-foreground/40" />
504	                                <span className="text-[10px] text-muted-foreground/60">
505	                                  {room.memberCount || 1} member{(room.memberCount || 1) !== 1 ? "s" : ""}
506	                                </span>
507	                                <Badge variant="outline" className="h-3.5 px-1 text-[8px] border-bronze/25 text-bronze/80 ml-auto leading-none">
508	                                  Active
509	                                </Badge>
510	                              </div>
511	                            </div>
512	                          </div>
513	                        </button>
514	
515	                        {/* ⋮ context menu */}
516	                        <DropdownMenu>
517	                          <DropdownMenuTrigger asChild>
518	                            <button
519	                              onClick={(e) => e.stopPropagation()}
520	                              className="mr-1.5 w-6 h-6 flex items-center justify-center rounded-lg opacity-0 group-hover:opacity-100 transition-opacity hover:bg-muted text-muted-foreground/60 hover:text-foreground flex-shrink-0"
521	                            >
522	                              <MoreHorizontal className="w-3.5 h-3.5" />
523	                            </button>
524	                          </DropdownMenuTrigger>
525	                          <DropdownMenuContent align="end" className="w-36">
526	                            <DropdownMenuItem
527	                              onClick={(e) => { e.stopPropagation(); setRenameValue(room.name ?? ""); setRenameDialog(room); }}
528	                              className="text-xs gap-2"
529	                            >
530	                              <Pencil className="w-3.5 h-3.5" /> Rename
531	                            </DropdownMenuItem>
532	                            <DropdownMenuSeparator />
533	                            <DropdownMenuItem
534	                              onClick={(e) => { e.stopPropagation(); setDeleteConfirm(room); }}
535	                              className="text-xs gap-2 text-destructive focus:text-destructive"
536	                            >
537	                              <Trash2 className="w-3.5 h-3.5" /> Delete
538	                            </DropdownMenuItem>
539	                          </DropdownMenuContent>
540	                        </DropdownMenu>
541	                      </motion.div>
542	                    );
543	                  })}
544	                </div>
545	              )}
546	            </div>
547	
548	            {/* Direct Messages */}
549	            <div>
550	              <div className="flex items-center justify-between px-2 py-1.5">
551	                <p className="text-[10px] font-semibold text-muted-foreground/50 uppercase tracking-widest">
552	                  Direct Messages
553	                </p>
554	                <button
555	                  onClick={openDmDialog}
556	                  title="New direct message"
557	                  className="w-5 h-5 flex items-center justify-center rounded-md text-muted-foreground/50 hover:text-foreground hover:bg-muted transition-all duration-150"
558	                >
559	                  <Plus className="w-3.5 h-3.5" />
560	                </button>
561	              </div>
562	
563	              {loading ? (
564	                <div className="space-y-0.5">
565	                  {[...Array(2)].map((_, i) => (
566	                    <SkeletonItem key={i} />
567	                  ))}
568	                </div>
569	              ) : dms.length === 0 ? (
570	                <div className="px-2 py-5 text-center">
571	                  <MessageSquare className="w-6 h-6 text-muted-foreground/20 mx-auto mb-2" />
572	                  <p className="text-[11px] text-muted-foreground">
573	                    No direct messages
574	                  </p>
575	                </div>
576	              ) : (
577	                <div className="space-y-0.5">
578	                  {dms.map((room) => {
579	                    const isSelected = selectedRoomId === room.id;
580	                    const name = room.dmPartnerName ?? "Unknown user";
581	                    const initial = room.dmPartnerInitial ?? name[0].toUpperCase();
582	                    return (
583	                      <div
584	                        key={room.id}
585	                        className={cn(
586	                          "relative flex items-center rounded-xl transition-all duration-150 group border",
587	                          isSelected
588	                            ? "bg-accent border-border"
589	                            : "hover:bg-gray-50 dark:hover:bg-muted/50 border-transparent"
590	                        )}
591	                      >
592	                        <button
593	                          onClick={() => onSelectRoom(room, "dm")}
594	                          className="flex-1 text-left p-2.5 min-w-0"
595	                        >
596	                          <div className="flex items-center gap-2.5">
597	                            <div
598	                              className="w-9 h-9 rounded-full flex items-center justify-center flex-shrink-0 overflow-hidden font-bold text-[13px]"
599	                              style={avatarStyle(room.memberUserIds?.find(id => id !== userId) || name)}
600	                            >
601	                              {room.dmPartnerAvatar ? (
602	                                <img
603	                                  src={room.dmPartnerAvatar}
604	                                  alt={name}
605	                                  className="w-full h-full object-cover"
606	                                  onError={(e) => { (e.target as HTMLImageElement).style.display = "none"; }}
607	                                />
608	                              ) : (
609	                                initial
610	                              )}
611	                            </div>
612	                            <div className="min-w-0 flex-1">
613	                              <div className="flex items-center justify-between gap-1 mb-0.5">
614	                                <p className="text-[12px] font-semibold truncate text-foreground/85">
615	                                  {name}
616	                                </p>
617	                                <span className="text-[9px] text-muted-foreground/50 whitespace-nowrap flex-shrink-0">
618	                                  {timeAgo(room.updated_at)}
619	                                </span>
620	                              </div>
621	                              <p className="text-[10px] text-muted-foreground/50">
622	                                Direct message
623	                              </p>
624	                            </div>
625	                          </div>
626	                        </button>
627	
628	                        {/* ⋮ context menu for DMs */}
629	                        <DropdownMenu>
630	                          <DropdownMenuTrigger asChild>
631	                            <button
632	                              onClick={(e) => e.stopPropagation()}
633	                              className="mr-1.5 w-6 h-6 flex items-center justify-center rounded-lg opacity-0 group-hover:opacity-100 transition-opacity hover:bg-muted text-muted-foreground/60 hover:text-foreground flex-shrink-0"
634	                            >
635	                              <MoreHorizontal className="w-3.5 h-3.5" />
636	                            </button>
637	                          </DropdownMenuTrigger>
638	                          <DropdownMenuContent align="end" className="w-36">
639	                            <DropdownMenuItem
640	                              onClick={(e) => { e.stopPropagation(); setDeleteConfirm(room); }}
641	                              className="text-xs gap-2 text-destructive focus:text-destructive"
642	                            >
643	                              <Trash2 className="w-3.5 h-3.5" /> Delete Chat
644	                            </DropdownMenuItem>
645	                          </DropdownMenuContent>
646	                        </DropdownMenu>
647	                      </div>
648	                    );
649	                  })}
650	                </div>
651	              )}
652	            </div>
653	          </div>
654	        </ScrollArea>
655	      </div>
656	
657	      {/* Create Workspace Dialog */}
658	      <Dialog open={createDialogOpen} onOpenChange={(o) => { if (!o) setCreateDialogOpen(false); }}>
659	        <DialogContent className="max-w-sm">
660	          <DialogHeader>
661	            <DialogTitle className="text-sm font-semibold">New Workspace</DialogTitle>
662	          </DialogHeader>
663	          <Input
664	            value={createName}
665	            onChange={(e) => setCreateName(e.target.value)}
666	            placeholder="e.g. Nike x Crevia Campaign"
667	            className="h-9 text-sm"
668	            autoFocus
669	            onKeyDown={(e) => { if (e.key === "Enter" && !creating) createWorkspace(); }}
670	          />
671	          <div className="flex gap-2 justify-end mt-1">
672	            <Button variant="outline" size="sm" onClick={() => setCreateDialogOpen(false)} disabled={creating}>
673	              Cancel
674	            </Button>
675	            <Button size="sm" onClick={createWorkspace} disabled={!createName.trim() || creating}
676	              className="bg-bronze hover:bg-bronze/90 text-background">
677	              {creating ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : "Create"}
678	            </Button>
679	          </div>
680	        </DialogContent>
681	      </Dialog>
682	
683	      {/* Rename Dialog */}
684	      <Dialog open={!!renameDialog} onOpenChange={(o) => { if (!o) setRenameDialog(null); }}>
685	        <DialogContent className="max-w-sm">
686	          <DialogHeader>
687	            <DialogTitle className="text-sm font-semibold">Rename Workspace</DialogTitle>
688	          </DialogHeader>
689	          <Input
690	            value={renameValue}
691	            onChange={(e) => setRenameValue(e.target.value)}
692	            placeholder="Workspace name"
693	            className="h-9 text-sm"
694	            autoFocus
695	            onKeyDown={(e) => { if (e.key === "Enter") handleRename(); }}
696	          />
697	          <div className="flex gap-2 justify-end mt-1">
698	            <Button variant="outline" size="sm" onClick={() => setRenameDialog(null)} disabled={renaming}>
699	              Cancel
700	            </Button>
701	            <Button size="sm" onClick={handleRename} disabled={!renameValue.trim() || renaming}
702	              className="bg-bronze hover:bg-bronze/90 text-background">
703	              {renaming ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : "Save"}
704	            </Button>
705	          </div>
706	        </DialogContent>
707	      </Dialog>
708	
709	      {/* Delete Confirmation */}
710	      <AlertDialog open={!!deleteConfirm} onOpenChange={(o) => { if (!o) setDeleteConfirm(null); }}>
711	        <AlertDialogContent>
712	          <AlertDialogHeader>
713	            <AlertDialogTitle className="text-sm font-semibold">
714	              {deleteConfirm?.name ? "Delete Workspace" : "Delete Chat"}
715	            </AlertDialogTitle>
716	            <AlertDialogDescription className="text-xs">
717	              Permanently delete{" "}
718	              <strong>{deleteConfirm?.name ?? deleteConfirm?.dmPartnerName ?? "this conversation"}</strong>{" "}
719	              and all its messages? This cannot be undone.
720	            </AlertDialogDescription>
721	          </AlertDialogHeader>
722	          <AlertDialogFooter>
723	            <AlertDialogCancel className="text-xs h-8">Cancel</AlertDialogCancel>
724	            <AlertDialogAction onClick={handleDelete} disabled={deleting}
725	              className="text-xs h-8 bg-destructive hover:bg-destructive/90 text-destructive-foreground">
726	              {deleting ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : "Delete"}
727	            </AlertDialogAction>
728	          </AlertDialogFooter>
729	        </AlertDialogContent>
730	      </AlertDialog>
731	
732	      {/* New DM Dialog */}
733	      <Dialog open={dmDialogOpen} onOpenChange={setDmDialogOpen}>
734	        <DialogContent className="max-w-sm">
735	          <DialogHeader>
736	            <DialogTitle className="text-sm font-semibold">
737	              New Direct Message
738	            </DialogTitle>
739	          </DialogHeader>
740	
741	          <div className="relative mb-3">
742	            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-muted-foreground/60" />
743	            <Input
744	              value={userSearch}
745	              onChange={(e) => setUserSearch(e.target.value)}
746	              placeholder="Search people..."
747	              className="pl-8 h-9 text-sm"
748	              autoFocus
749	            />
750	          </div>
751	
752	          <ScrollArea className="max-h-64">
753	            {loadingUsers ? (
754	              <div className="flex items-center justify-center py-8">
755	                <Loader2 className="w-5 h-5 animate-spin text-muted-foreground" />
756	              </div>
757	            ) : filteredUsers.length === 0 ? (
758	              <div className="text-center py-8">
759	                <p className="text-sm text-muted-foreground">No users found</p>
760	              </div>
761	            ) : (
762	              <div className="space-y-0.5 pr-2">
763	                {filteredUsers.map((user) => {
764	                  const name =
765	                    user.display_name ||
766	                    (user.handle ? `@${user.handle}` : "Unknown");
767	                  const initial = name[0].toUpperCase();
768	                  const isStarting = startingDM === user.id;
769	                  return (
770	                    <button
771	                      key={user.id}
772	                      onClick={() => startDirectChat(user.id)}
773	                      disabled={!!startingDM}
774	                      className="w-full flex items-center gap-3 p-2.5 rounded-xl hover:bg-muted transition-all duration-150 text-left disabled:opacity-60"
775	                    >
776	                      <div
777	                        className="w-9 h-9 rounded-full flex items-center justify-center flex-shrink-0 overflow-hidden font-bold text-[13px]"
778	                        style={avatarStyle(user.id)}
779	                      >
780	                        {user.avatar_url ? (
781	                          <img
782	                            src={user.avatar_url}
783	                            alt={name}
784	                            className="w-full h-full object-cover rounded-full"
785	                            onError={(e) => { (e.target as HTMLImageElement).style.display = "none"; }}
786	                          />
787	                        ) : (
788	                          initial
789	                        )}
790	                      </div>
791	                      <div className="min-w-0 flex-1">
792	                        <p className="text-sm font-medium truncate">{name}</p>
793	                        {user.handle && (
794	                          <p className="text-xs text-muted-foreground truncate">
795	                            @{user.handle}
796	                          </p>
797	                        )}
798	                      </div>
799	                      {isStarting && (
800	                        <Loader2 className="w-4 h-4 animate-spin text-muted-foreground flex-shrink-0" />
801	                      )}
802	                    </button>
803	                  );
804	                })}
805	              </div>
806	            )}
807	          </ScrollArea>
808	        </DialogContent>
809	      </Dialog>
810	    </>
811	  );
812	};
813	
814	export default WorkspaceInboxList;
