import { useSearchParams } from "react-router-dom";
import { Link2, MessageSquare, Sparkles, Settings, Receipt, FileSignature } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";
import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";

// Tab content
import CreviaLink from "./CreviaLink";
import SmartInvoicesTab from "@/components/studio/SmartInvoicesTab";
import ContractsTab from "@/components/studio/ContractsTab";
import StudioSettingsTab from "@/components/studio/StudioSettingsTab";
import StudioWorkspacesHub from "@/components/studio/workspaces/StudioWorkspacesHub";

const CreviaStudio = () => {
  const [searchParams, setSearchParams] = useSearchParams();

  const activeTab = searchParams.get("tab") || "link";
  const activeLinkSection = searchParams.get("section") || "profile";
  const activeWorkspace = searchParams.get("workspace") || undefined;
  const activeRoomId = searchParams.get("roomId") || undefined;

  // Strict order: Link → Workspace → Invoice → Contracts → Settings
  const studioTabs = [
    { id: "link",      label: "Crevia Link", icon: Link2 },
    { id: "chat",      label: "Workspace",   icon: MessageSquare },
    { id: "invoices",  label: "Invoice",     icon: Receipt },
    { id: "contracts", label: "Canvas",       icon: FileSignature },
    { id: "settings",  label: "Settings",    icon: Settings },
  ];

  const linkSections = [
    { id: "profile",    label: "Profile" },
    { id: "buttons",    label: "Buttons" },
    { id: "appearance", label: "Appearance" },
    { id: "settings",   label: "Settings" },
    { id: "analytics",  label: "Analytics" },
  ];

  const handleTabChange = (tabId: string) => {
    setSearchParams({ tab: tabId });
  };

  const handleLinkSectionChange = (sectionId: string) => {
    setSearchParams({ tab: "link", section: sectionId });
  };

  const isChatTab = activeTab === "chat";

  return (
    <div className="h-full flex flex-col bg-background">
      {/* Studio Header — flex-shrink-0 keeps it pinned while content below scrolls */}
      <div className="border-b border-border bg-background z-30 flex-shrink-0">
        <div className="mx-auto w-full max-w-7xl px-4 py-3 md:px-6 md:py-4">
          <div className="flex items-center gap-3 mb-3 md:mb-4">
            <div className="p-1.5 md:p-2 rounded-xl bg-bronze/10">
              <Sparkles className="h-4 w-4 md:h-5 md:w-5 text-bronze" />
            </div>
            <div>
              <h1 className="font-vollkorn text-xl md:text-2xl font-semibold text-foreground">
                Crevia Studio
              </h1>
              <p className="text-sm md:text-base text-muted-foreground">
                Your creative business toolkit
              </p>
            </div>
          </div>

          {/* Tabs — strict order enforced by studioTabs array */}
          <ScrollArea className="w-full">
            <div className="flex items-center gap-1 pb-1 -mb-px">
              {studioTabs.map((tab) => {
                const Icon = tab.icon;
                const isActive = activeTab === tab.id;
                return (
                  <button
                    key={tab.id}
                    onClick={() => handleTabChange(tab.id)}
                    title={tab.label}
                    className={cn(
                      "flex items-center gap-1.5 px-3 py-2.5 rounded-t-lg font-poppins text-sm font-medium whitespace-nowrap transition-all duration-300 min-w-[44px] justify-center",
                      isActive
                        ? "bg-bronze/10 text-bronze border-b-2 border-bronze"
                        : "text-muted-foreground hover:text-foreground hover:bg-muted/50"
                    )}
                  >
                    <Icon className="h-4 w-4 flex-shrink-0" />
                    <span className="hidden sm:inline">{tab.label}</span>
                  </button>
                );
              })}
            </div>
            <ScrollBar orientation="horizontal" className="h-1.5" />
          </ScrollArea>

          {/* Link sub-sections (mobile only) — segmented control */}
          {activeTab === "link" && (
            <div className="md:hidden mt-2 border-t border-border/40 pt-2">
              {/* Row 1: Profile · Buttons · Appearance */}
              <div className="flex gap-1 p-1 bg-muted/60 rounded-xl mb-1">
                {linkSections.slice(0, 3).map((section) => (
                  <button
                    key={section.id}
                    type="button"
                    onClick={() => handleLinkSectionChange(section.id)}
                    className={cn(
                      "flex-1 py-1.5 rounded-lg text-[11px] font-semibold text-center transition-all duration-200 active:scale-95",
                      activeLinkSection === section.id
                        ? "bg-background text-foreground shadow-sm"
                        : "text-muted-foreground"
                    )}
                  >
                    {section.label}
                  </button>
                ))}
              </div>
              {/* Row 2: Settings · Analytics */}
              <div className="flex gap-1 p-1 bg-muted/60 rounded-xl">
                {linkSections.slice(3).map((section) => (
                  <button
                    key={section.id}
                    type="button"
                    onClick={() => handleLinkSectionChange(section.id)}
                    className={cn(
                      "flex-1 py-1.5 rounded-lg text-[11px] font-semibold text-center transition-all duration-200 active:scale-95",
                      activeLinkSection === section.id
                        ? "bg-background text-foreground shadow-sm"
                        : "text-muted-foreground"
                    )}
                  >
                    {section.label}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Tab Content */}
      {isChatTab ? (
        <div className="flex-1 min-h-0 overflow-hidden">
          <StudioWorkspacesHub initialRoomId={activeRoomId} />
        </div>
      ) : (
        <div className="flex-1 overflow-y-auto min-w-0">
          <AnimatePresence mode="wait">
            <motion.div
              key={activeTab}
              initial={{ opacity: 0, y: 8 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -6 }}
              transition={{ duration: 0.3, ease: [0.25, 0.46, 0.45, 0.94] }}
            >
              {activeTab === "link"      && <CreviaLink isEmbedded />}
              {activeTab === "invoices"  && <SmartInvoicesTab workspaceId={activeWorkspace} />}
              {activeTab === "contracts" && <ContractsTab workspaceId={activeWorkspace} />}
              {activeTab === "settings"  && <StudioSettingsTab />}
            </motion.div>
          </AnimatePresence>
        </div>
      )}
    </div>
  );
};

export default CreviaStudio;

import { Link, useLocation, useNavigate } from "react-router-dom";
import { Home, Sparkles, MoreHorizontal, Briefcase, Crown, Download } from "lucide-react";
import { cn } from "@/lib/utils";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "@/components/ui/sheet";
import { Button } from "@/components/ui/button";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Separator } from "@/components/ui/separator";
import { ScrollArea } from "@/components/ui/scroll-area";
import { supabase } from "@/integrations/supabase/client";
import { useState, useEffect } from "react";
import { useLanguage } from "@/i18n/LanguageContext";
import { usePWAInstall } from "@/hooks/use-pwa-install";

const MobileBottomNav = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { t } = useLanguage();
  const [profile, setProfile] = useState<any>(null);
  const [sheetOpen, setSheetOpen] = useState(false);
  const { canInstall, install } = usePWAInstall();

  useEffect(() => {
    const fetchProfile = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (session) {
        const { data: profileData } = await supabase
          .from("profiles")
          .select("*")
          .eq("id", session.user.id)
          .single();
        setProfile(profileData);
      }
    };
    fetchProfile();
  }, []);

  const isActive = (path: string) => {
    return location.pathname === path || location.pathname.startsWith(path + "/");
  };

  const handleSignOut = async () => {
    await supabase.auth.signOut();
    navigate("/");
    setSheetOpen(false);
  };

  const handleNavigation = (path: string) => {
    navigate(path);
    setSheetOpen(false);
  };

  const navItems = [
    { id: "kira", label: "Kira", icon: Sparkles, path: "/kira" },
    { id: "studio", label: "Studio", icon: Briefcase, path: "/crevia-studio" },
  ];

  return (
    <nav className="md:hidden fixed bottom-0 left-0 right-0 z-50 bg-black border-t border-white/10 safe-area-pb">
      <div className="grid grid-cols-3 h-16">
        {navItems.map((item) => {
          const Icon = item.icon;
          const active = isActive(item.path);

          return (
            <Link
              key={item.id}
              to={item.path}
              className={cn(
                "flex flex-col items-center justify-center gap-1 transition-all duration-[400ms] ease-[cubic-bezier(0.32,0.72,0,1)] group",
                active ? "text-bronze" : "text-white/60"
              )}
            >
              <Icon className={cn(
                "h-5 w-5 transition-all duration-[400ms] ease-[cubic-bezier(0.32,0.72,0,1)] group-hover:scale-110", 
                active && "drop-shadow-[0_0_8px_rgba(207,129,80,0.5)]"
              )} />
              <span className="font-poppins text-xs font-medium">{item.label}</span>
            </Link>
          );
        })}

        <Sheet open={sheetOpen} onOpenChange={setSheetOpen}>
          <SheetTrigger asChild>
            <button className="flex flex-col items-center justify-center gap-1 text-white/60">
              <MoreHorizontal className="h-5 w-5" />
              <span className="font-poppins text-xs font-medium">{t("common.more")}</span>
            </button>
          </SheetTrigger>
          <SheetContent side="bottom" className="bg-black border-white/10 h-[85dvh] max-h-[85dvh] flex flex-col p-0">
            <SheetHeader className="px-4 pt-4 pb-2 flex-shrink-0">
              <SheetTitle className="text-white font-vollkorn text-lg">{t("nav.moreOptions")}</SheetTitle>
            </SheetHeader>

            <ScrollArea className="flex-1 px-4">
              {profile && (
                <div className="flex items-center gap-3 p-3 sm:p-4 rounded-2xl bg-gradient-to-br from-white/10 to-white/5 border border-white/10 mb-4">
                  <Avatar className="h-11 w-11 sm:h-12 sm:w-12 ring-2 ring-bronze/30 flex-shrink-0">
                    <AvatarImage src={profile?.avatar_url} />
                    <AvatarFallback className="bg-gradient-to-br from-bronze to-bronze-dark text-white font-semibold text-sm">
                      {profile?.display_name?.charAt(0) || profile?.email?.charAt(0) || "U"}
                    </AvatarFallback>
                  </Avatar>
                  <div className="flex-1 min-w-0">
                    <p className="font-poppins text-sm font-semibold text-white truncate">
                      {profile?.display_name || "User"}
                    </p>
                    <p className="text-xs text-white/50 truncate">{profile?.email}</p>
                  </div>
                </div>
              )}

              <div className="space-y-4 pb-8">

                {/* Upgrade to Pro — always visible */}
                <Link
                  to="/pricing"
                  onClick={() => setSheetOpen(false)}
                  className="flex items-center gap-3 px-4 py-3.5 rounded-xl bg-gradient-to-r from-bronze to-bronze-dark text-white hover:opacity-90 transition-all w-full"
                >
                  <Crown className="h-5 w-5 flex-shrink-0" />
                  <span className="font-poppins text-sm font-semibold">Upgrade to Pro</span>
                </Link>

                {/* Install app — only shown when browser supports it and app isn't installed */}
                {canInstall && (
                  <button
                    onClick={() => { install(); setSheetOpen(false); }}
                    className="flex items-center gap-3 px-4 py-3.5 rounded-xl bg-white/5 border border-white/10 text-white hover:bg-white/10 transition-all w-full"
                  >
                    <Download className="h-5 w-5 flex-shrink-0 text-bronze" />
                    <div className="text-left">
                      <p className="font-poppins text-sm font-semibold">Install Crevia App</p>
                      <p className="text-[11px] text-white/50">Add to home screen</p>
                    </div>
                  </button>
                )}

                <Separator className="bg-white/10" />

                <div className="space-y-1">
                  <p className="text-[10px] font-medium text-white/40 uppercase tracking-wider px-2 mb-1">{t("nav.account")}</p>
                  <Button 
                    variant="ghost" 
                    className="w-full justify-start text-white/90 hover:text-bronze hover:bg-white/5 h-11 text-sm font-medium rounded-xl"
                    onClick={() => handleNavigation("/profile/settings")}
                  >
                    {t("profile.settings")}
                  </Button>
                  <Button 
                    variant="ghost" 
                    className="w-full justify-start text-white/90 hover:text-bronze hover:bg-white/5 h-11 text-sm font-medium rounded-xl"
                    onClick={() => handleNavigation("/profile/payments-billing")}
                  >
                    {t("profile.paymentsBilling")}
                  </Button>
                  <Button 
                    variant="ghost" 
                    className="w-full justify-start text-white/90 hover:text-bronze hover:bg-white/5 h-11 text-sm font-medium rounded-xl"
                    onClick={() => handleNavigation("/profile/feedback")}
                  >
                    {t("nav.feedback")}
                  </Button>
                </div>

                <Separator className="bg-white/10" />

                <div className="space-y-1">
                  <p className="text-[10px] font-medium text-white/40 uppercase tracking-wider px-2 mb-1">{t("nav.support")}</p>
                  <Button 
                    variant="ghost" 
                    className="w-full justify-start text-white/90 hover:text-bronze hover:bg-white/5 h-11 text-sm font-medium rounded-xl"
                    onClick={() => handleNavigation("/profile/help")}
                  >
                    {t("nav.helpSupport")}
                  </Button>
                  <Button 
                    variant="ghost" 
                    className="w-full justify-start text-white/90 hover:text-bronze hover:bg-white/5 h-11 text-sm font-medium rounded-xl"
                    onClick={() => handleNavigation("/app/about")}
                  >
                    {t("nav.aboutCrevia")}
                  </Button>
                </div>

                <Separator className="bg-white/10" />

                <div className="space-y-1">
                  <p className="text-[10px] font-medium text-white/40 uppercase tracking-wider px-2 mb-1">{t("nav.legal")}</p>
                  <div className="flex gap-2">
                    <Button 
                      variant="ghost" 
                      className="flex-1 text-white/60 hover:text-bronze hover:bg-white/5 h-11 text-xs font-medium rounded-xl"
                      onClick={() => handleNavigation("/privacy-policy")}
                    >
                      {t("nav.privacy")}
                    </Button>
                    <Button 
                      variant="ghost" 
                      className="flex-1 text-white/60 hover:text-bronze hover:bg-white/5 h-11 text-xs font-medium rounded-xl"
                      onClick={() => handleNavigation("/terms-of-service")}
                    >
                      {t("nav.terms")}
                    </Button>
                  </div>
                </div>

                <Separator className="bg-white/10" />

                <Button 
                  variant="ghost" 
                  className="w-full justify-start text-red-400 hover:text-red-300 hover:bg-red-500/10 h-11 text-sm font-medium rounded-xl"
                  onClick={handleSignOut}
                >
                  {t("nav.logOut")}
                </Button>
              </div>
            </ScrollArea>
          </SheetContent>
        </Sheet>
      </div>
    </nav>
  );
};

export default MobileBottomNav;

